const LOGO_B64 = "";
const BUILDING_B64 = "";
const LETTRE_B64 = "";
const TROPHY_B64 = "";
const CLASSROOM_B64 = "";
document.querySelectorAll('.brand-logo-img, .hero-logo-img').forEach(img => { img.src = 'data:image/jpeg;base64,' + LOGO_B64; });
document.documentElement.style.setProperty('--building-url', "url('data:image/jpeg;base64," + BUILDING_B64 + "')");
document.querySelectorAll('.lettre-img').forEach(img => { img.src = 'data:image/jpeg;base64,' + LETTRE_B64; });
document.querySelectorAll('.trophy-img').forEach(img => { img.src = 'data:image/jpeg;base64,' + TROPHY_B64; });
document.querySelectorAll('.classroom-img').forEach(img => { img.src = 'data:image/jpeg;base64,' + CLASSROOM_B64; });
